```python
from typing import Dict, Any, List, TypedDict
from pydantic import BaseModel, Field

# Define the grading models for documents, hallucinations, and answers
class GradeDocuments(BaseModel):
    """Binary score for relevance check on retrieved documents."""
    binary_score: str = Field(..., description="Documents are relevant to the question, 'yes' or 'no'")

class GradeHallucinations(BaseModel):
    """Binary score for hallucination check in generated responses."""
    binary_score: str = Field(..., description="Response is based on factual information, 'yes' or 'no'")

class GradeAnswer(BaseModel):
    """Binary score to evaluate if the response addresses the question."""
    binary_score: str = Field(..., description="Response addresses the question, 'yes' or 'no'")

# Define the state schema
class GraphState(TypedDict):
    """Represents the current state of the processing graph."""
    question: str
    generation: str
    documents: List[str]
    iterations: int = 0

class DataProcessingAgent:
    def __init__(self, cloud_credentials: Dict[str, str], region: str = "default-region"):
        self.cloud_credentials = cloud_credentials
        self.region = region
        self.llm = self.initialize_llm()
        self.retriever = self.initialize_retriever()
        self.document_grader = self.initialize_document_grader()
        self.hallucination_grader = self.initialize_hallucination_grader()
        self.answer_grader = self.initialize_answer_grader()
        self.rag_prompt = self.initialize_rag_prompt()
        self.question_rewriter_prompt = self.initialize_question_rewriter_prompt()
        self.workflow = self.initialize_workflow()
        self.app = self.workflow.compile()

    def initialize_llm(self):
        return ChatModel(
            model_id="generic-model-identifier",
            model_kwargs={"max_tokens": 10000, "temperature": 0, "top_p": 1},
            region_name=self.region
        )

    def initialize_retriever(self):
        return DocumentRetriever(
            credentials=self.cloud_credentials,
            persist_directory="./storage_db",
            collection_name="sample_collection",
            embedding_provider="generic_embedding_service",
            top_n=3
        )

    def initialize_document_grader(self) -> ChatPromptTemplate:
        system_prompt = "You are an evaluator determining if a retrieved document is relevant to a user question. If the document contains related keywords or meaning, mark as relevant. Respond with 'yes' or 'no'."
        return self.create_chat_prompt(system_prompt, "Retrieved document: \n\n {document} \n\n User question: {question}", GradeDocuments)

    def initialize_hallucination_grader(self) -> ChatPromptTemplate:
        system_prompt = "You are an evaluator checking if a generated response is supported by a set of retrieved facts. Provide a binary score 'yes' or 'no'. 'Yes' indicates the response is grounded in facts."
        return self.create_chat_prompt(system_prompt, "Set of facts: \n\n {documents} \n\n Generated response: {generation}", GradeHallucinations)

    def initialize_answer_grader(self) -> ChatPromptTemplate:
        system_prompt = "You are an evaluator determining if a response effectively answers the question. Provide a binary score 'yes' or 'no'. 'Yes' indicates the response resolves the question."
        return self.create_chat_prompt(system_prompt, "User question: \n\n {question} \n\n Generated response: {generation}", GradeAnswer)

    def create_chat_prompt(self, system_prompt: str, user_prompt: str, output_model: BaseModel) -> ChatPromptTemplate:
        return ChatPromptTemplate.from_messages([
            ("system", system_prompt),
            ("human", user_prompt)
        ]) | self.llm.with_structured_output(output_model)

    def initialize_rag_prompt(self) -> PromptTemplate:
        return PromptTemplate(
            input_variables=["question", "context"],
            template=(
                "You are an assistant for question-answering tasks. "
                "Use the following retrieved context to answer the question. "
                "If unsure, state that you don't know. "
                "Question: {question} \n"
                "Context: {context} \n"
                "Answer:"
            )
        )

    def initialize_question_rewriter_prompt(self) -> ChatPromptTemplate:
        return ChatPromptTemplate.from_messages([
            ("system", "You are a question rephrasing tool to improve retrieval."),
            ("human", "Given the question: {question}, rewrite it to enhance retrieval effectiveness.")
        ])

    def initialize_workflow(self):
        state_schema = GraphState
        workflow = StateGraph(state_schema=state_schema)
        max_iterations = 2

        workflow.add_node("retrieve", self.retrieve)
        workflow.add_node("grade_documents", self.grade_documents)
        workflow.add_node("generate", self.generate)
        workflow.add_node("transform_query", self.transform_query)

        workflow.add_edge(START, "retrieve")
        workflow.add_edge("retrieve", "grade_documents")
        workflow.add_conditional_edges("grade_documents", self.decide_to_generate, {
            "transform_query": "transform_query",
            "generate": "generate"
        })
        workflow.add_edge("transform_query", "retrieve")
        workflow.add_conditional_edges("generate", self.REDACTED_TOKEN, {
            "not supported": "generate",
            "useful": END,
            "not useful": "transform_query",
            "exit": END
        })

        return workflow

    def retrieve(self, state: Dict[str, Any]) -> Dict[str, Any]:
        print("---RETRIEVE---")
        question = state["question"]
        docs = self.retriever.retrieve_with_compression(question, k=25)
        return {"documents": docs, "question": question, "iterations": state["iterations"]}

    def generate(self, state: Dict[str, Any]) -> Dict[str, Any]:
        print("---GENERATE---")
        question = state["question"]
        documents = state["documents"]
        generation = self.rag_chain.invoke({"context": documents, "question": question})
        print(f"Generated Response: {generation}\n")
        return {"documents": documents, "question": question, "generation": generation}

    def grade_documents(self, state: Dict[str, Any]) -> Dict[str, Any]:
        print("---CHECK DOCUMENT RELEVANCE---")
        question = state["question"]
        documents = state["documents"]
        filtered_docs = []

        for doc in documents:
            score = self.document_grader.invoke({"question": question, "document": doc.page_content})
            if score.binary_score == "yes":
                print("---GRADE: DOCUMENT RELEVANT---")
                filtered_docs.append(doc)
            else:
                print("---GRADE: DOCUMENT NOT RELEVANT---")

        return {"documents": filtered_docs, "question": question}

    def transform_query(self, state: Dict[str, Any]) -> Dict[str, Any]:
        print("---TRANSFORM QUERY---")
        question = state["question"]
        new_question = self.question_rewriter.invoke({"question": question})

        if isinstance(new_question, str):
            state["question"] = new_question
            state["iterations"] += 1

        return {"documents": state["documents"], "question": new_question, "iterations": state["iterations"]}

    def decide_to_generate(self, state: GraphState) -> str:
        print("---ASSESS GRADED DOCUMENTS---")
        iterations = state["iterations"]

        if iterations >= 2:
            print("---DECISION: MAX ITERATIONS REACHED, END PROCESS---")
            return "generate"

        if not state["documents"]:
            print("---DECISION: NO RELEVANT DOCUMENTS, TRANSFORM QUERY---")
            return "transform_query"
        else:
            print("---DECISION: RELEVANT DOCUMENTS FOUND, GENERATE RESPONSE---")
            return "generate"

    def REDACTED_TOKEN(self, state: Dict[str, Any]) -> str:
        print("---CHECK SUPPORT AND RELEVANCE---")
        generation_score = self.hallucination_grader.invoke({"documents": state["documents"], "generation": state["generation"]})

        if generation_score.binary_score == "yes":
            answer_score = self.answer_grader.invoke({"question": state["question"], "generation": state["generation"]})
            if answer_score.binary_score == "yes":
                print("---DECISION: RESPONSE ADDRESSES QUESTION---")
                return "useful"
            else:
                print("---DECISION: RESPONSE DOES NOT ADDRESS QUESTION---")
                return "not useful"
        else:
            print("---DECISION: RESPONSE NOT GROUNDED, RE-TRY---")
            return "not supported"

    def process_question(self, question: str):
        inputs = {"question": question, "iterations": 0}
        for output in self.app.stream(inputs):
            for key, value in output.items():
                print(f"Node '{key}': {value}\n---\n")

# Example usage:
cloud_credentials = {
    'access_key_id': 'your_access_key',
    'secret_access_key': 'your_secret_key',
    'session_token': 'your_session_token',
    'region_name': 'default-region'
}

sample_question = "Sample question?"
# Initialize the agent
agent = DataProcessingAgent(cloud_credentials)

# Process a question
agent.process_question(sample_question)
```

