                print("---GRADE: DOCUMENT RELEVANT---")
                filtered_docs.append(doc)
            else:
                print("---GRADE: DOCUMENT NOT RELEVANT---")

        return {"documents": filtered_docs, "question": question}

    def transform_query(self, state: Dict[str, Any]) -> Dict[str, Any]:
        print("---TRANSFORM QUERY---")
        question = state["question"]
        new_question = self.question_rewriter.invoke({"question": question})

        if isinstance(new_question, str):
            state["question"] = new_question
            state["iterations"] += 1

        return {"documents": state["documents"], "question": new_question, "iterations": state["iterations"]}

    def decide_to_generate(self, state: GraphState) -> str:
        print("---ASSESS GRADED DOCUMENTS---")
        iterations = state["iterations"]

        if iterations >= 2:
            print("---DECISION: MAX ITERATIONS REACHED, END PROCESS---")
            return "generate"

        if not state["documents"]:
            print("---DECISION: NO RELEVANT DOCUMENTS, TRANSFORM QUERY---")
            return "transform_query"
        else:
            print("---DECISION: RELEVANT DOCUMENTS FOUND, GENERATE ANSWER---")
            return "generate"

    def REDACTED_TOKEN(self, state: Dict[str, Any]) -> str:
        print("---CHECK HALLUCINATIONS AND ANSWER RELEVANCE---")
        generation_score = self.hallucination_grader.invoke({"documents": state["documents"], "generation": state["generation"]})

        if generation_score.binary_score == "yes":
            answer_score = self.answer_grader.invoke({"question": state["question"], "generation": state["generation"]})
            if answer_score.binary_score == "yes":
                print("---DECISION: GENERATION ADDRESSES QUESTION---")
                return "useful"
            else:
                print("---DECISION: GENERATION DOES NOT ADDRESS QUESTION---")
                return "not useful"
        else:
            print("---DECISION: GENERATION IS NOT GROUNDED IN DOCUMENTS, RE-TRY---")
            return "not supported"

    def process_question(self, question: str):
        inputs = {"question": question, "iterations": 0}
        for output in self.app.stream(inputs):
            for key, value in output.items():
                print(f"Node '{key}': {value}\n---\n")

